+	}
+	if ( !packet_handler.init(parameters.device_id, parameters.sigslots_namespace, device_type) ) {
+		throw ecl::StandardException(LOC,ecl::OpenError);
+	}
+	reset();
+	#endif
+
+	last_tick_left=0;
