+ * Refer to CruizCoreNodelet for an example use case.
+ *
+ * @sa CruizCoreNodelet
+ *
+ * @return bool : success or failure of the scan.
+ */
+
+void iClebo::runnable()
+{
+    unsigned char buf[256];
+    bool get_packet;
+	bool dummy_mode=false;
+
+    while(is_running)
+    {
+	pubtime("every_tick");
+	//std::cout << "." << std::flush;
