+		//if( verbose ) data.showMe();
+		//data.showMe();
+		if( protocol_version == "1.0" ) {
+			sig_sensor_data.emit();
+			sig_wheel_state.emit();
+		}
+		if( protocol_version == "2.0" ) {
+			std::set<unsigned char>::iterator it;
