+  Eigen::Vector3f axis = angle_axis.axis();
+
+  if( axis(2) > 0.0 ) heading = angle_axis.angle();
+  else if( axis(2) < 0.0 ) heading = -1.0 * angle_axis.angle();
+
+  angle += fabs(ecl::wrap_angle(heading - heading_last));
+  heading_last = heading;
+  
+  //std::cout << "." ;
+}
